import{_ as e,c as t,o,V as a}from"./chunks/framework.CwimN0wr.js";const g=JSON.parse('{"title":"Base Item","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/mixins/mixins.base-item.md","filePath":"api/core/mixins/mixins.base-item.md"}'),i={name:"api/core/mixins/mixins.base-item.md"},d=a('<h1 id="base-item" tabindex="-1">Base Item <a class="header-anchor" href="#base-item" aria-label="Permalink to &quot;Base Item&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>baseItem</code> mixin provides the foundation for list/collection item components. It manages the item&#39;s display properties (name, description, avatar), handles action binding and filtering based on the current user&#39;s abilities, and exposes helpers for common CRUD operations (view, edit, remove, export).</p><p>Actions are re-evaluated whenever the <code>item</code> or <code>actions</code> props change, and whenever user abilities are updated.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { baseItem } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@kalisio/kdk/core/client&#39;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  mixins: [baseItem],</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="emits" tabindex="-1">Emits <a class="header-anchor" href="#emits" aria-label="Permalink to &quot;Emits&quot;">​</a></h2><table><thead><tr><th>Event</th><th>Payload</th><th>Description</th></tr></thead><tbody><tr><td><code>item-selected</code></td><td><code>(item, section)</code></td><td>Emitted when the item is selected.</td></tr><tr><td><code>item-toggled</code></td><td><code>(item, toggled)</code></td><td>Emitted when the item&#39;s toggle state changes.</td></tr><tr><td><code>item-expanded</code></td><td><code>(item, expanded)</code></td><td>Emitted when the item is expanded or collapsed.</td></tr></tbody></table><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><table><thead><tr><th>Prop</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>service</code></td><td><code>String</code></td><td>yes</td><td>—</td><td>The name of the FeathersJS service this item belongs to. Used for permission checks and CRUD operations.</td></tr><tr><td><code>item</code></td><td><code>Object</code></td><td>yes</td><td>—</td><td>The data object represented by this item.</td></tr><tr><td><code>actions</code></td><td><code>Object | Array</code></td><td>no</td><td><code>null</code></td><td>Action definitions to display on the item.</td></tr><tr><td><code>filter</code></td><td><code>Object</code></td><td>no</td><td><code>{}</code></td><td>A <a href="https://github.com/crcn/sift.js" target="_blank" rel="noreferrer">sift</a> filter applied to the action list.</td></tr><tr><td><code>handlerContext</code></td><td><code>Object</code></td><td>no</td><td><code>null</code></td><td>The context object to which action handler methods are bound. Defaults to the component instance.</td></tr><tr><td><code>options</code></td><td><code>Object</code></td><td>no</td><td><code>{}</code></td><td>Display options. Supports <code>nameField</code>, <code>descriptionField</code>, and <code>avatar</code> keys.</td></tr><tr><td><code>bindActions</code></td><td><code>Boolean</code></td><td>no</td><td><code>true</code></td><td>When <code>true</code>, action handlers are bound to <code>handlerContext</code> (or the component instance). Set to <code>false</code> to skip binding.</td></tr></tbody></table><h2 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h2><table><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>itemActions</code></td><td><code>Array | null</code></td><td><code>null</code></td><td>The currently active, filtered, and bound actions for this item.</td></tr></tbody></table><h2 id="computed-properties" tabindex="-1">Computed Properties <a class="header-anchor" href="#computed-properties" aria-label="Permalink to &quot;Computed Properties&quot;">​</a></h2><h3 id="name" tabindex="-1"><code>name</code> <a class="header-anchor" href="#name" aria-label="Permalink to &quot;`name`&quot;">​</a></h3><p>Returns the item&#39;s display name, read from <code>item[options.nameField]</code> (defaults to <code>item.name</code>).</p><ul><li><strong>Returns:</strong> <code>string</code></li></ul><h3 id="description" tabindex="-1"><code>description</code> <a class="header-anchor" href="#description" aria-label="Permalink to &quot;`description`&quot;">​</a></h3><p>Returns the item&#39;s description, read from <code>item[options.descriptionField]</code> (defaults to <code>item.description</code>).</p><ul><li><strong>Returns:</strong> <code>string</code></li></ul><h3 id="avatar" tabindex="-1"><code>avatar</code> <a class="header-anchor" href="#avatar" aria-label="Permalink to &quot;`avatar`&quot;">​</a></h3><p>Returns whether an avatar should be displayed for this item, read from <code>options.avatar</code> (defaults to <code>true</code>).</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="setactions-actions" tabindex="-1"><code>setActions(actions)</code> <a class="header-anchor" href="#setactions-actions" aria-label="Permalink to &quot;`setActions(actions)`&quot;">​</a></h3><p>Binds the given action definitions to the handler context (or the component instance) and stores them in <code>itemActions</code>. Each item gets a deep clone of the action config to avoid shared state across items.</p><ul><li><strong>Parameters:</strong><ul><li><code>actions</code> <em>(Array | Object)</em>: The action definitions to bind.</li></ul></li></ul><h3 id="clearactions" tabindex="-1"><code>clearActions()</code> <a class="header-anchor" href="#clearactions" aria-label="Permalink to &quot;`clearActions()`&quot;">​</a></h3><p>Sets <code>itemActions</code> to <code>null</code>, removing all actions from the item.</p><h3 id="filteredactions" tabindex="-1"><code>filteredActions()</code> <a class="header-anchor" href="#filteredactions" aria-label="Permalink to &quot;`filteredActions()`&quot;">​</a></h3><p>Returns the subset of <code>actions</code> that pass the current <code>filter</code>.</p><ul><li><strong>Returns:</strong> <code>Array</code> — filtered action definitions, or an empty array if no actions are defined.</li></ul><h3 id="configureactions" tabindex="-1"><code>configureActions()</code> <a class="header-anchor" href="#configureactions" aria-label="Permalink to &quot;`configureActions()`&quot;">​</a></h3><p>Applies the filter and sets or clears <code>itemActions</code>. Override this method in concrete item components to implement custom action registration logic.</p><h3 id="onitemtoggled-toggled" tabindex="-1"><code>onItemToggled(toggled)</code> <a class="header-anchor" href="#onitemtoggled-toggled" aria-label="Permalink to &quot;`onItemToggled(toggled)`&quot;">​</a></h3><p>Emits the <code>item-toggled</code> event.</p><ul><li><strong>Parameters:</strong><ul><li><code>toggled</code> <em>(boolean)</em>: The new toggle state.</li></ul></li></ul><h3 id="onitemselected-section" tabindex="-1"><code>onItemSelected(section)</code> <a class="header-anchor" href="#onitemselected-section" aria-label="Permalink to &quot;`onItemSelected(section)`&quot;">​</a></h3><p>Emits the <code>item-selected</code> event.</p><ul><li><strong>Parameters:</strong><ul><li><code>section</code> <em>(any)</em>: The section or context in which the item was selected.</li></ul></li></ul><h3 id="onitemexpanded-expanded" tabindex="-1"><code>onItemExpanded(expanded)</code> <a class="header-anchor" href="#onitemexpanded-expanded" aria-label="Permalink to &quot;`onItemExpanded(expanded)`&quot;">​</a></h3><p>Emits the <code>item-expanded</code> event.</p><ul><li><strong>Parameters:</strong><ul><li><code>expanded</code> <em>(boolean)</em>: Whether the item is now expanded.</li></ul></li></ul><h3 id="canviewitem" tabindex="-1"><code>canViewItem()</code> <a class="header-anchor" href="#canviewitem" aria-label="Permalink to &quot;`canViewItem()`&quot;">​</a></h3><p>Checks whether the current user has <code>read</code> permission for this item.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="viewitem" tabindex="-1"><code>viewItem()</code> <a class="header-anchor" href="#viewitem" aria-label="Permalink to &quot;`viewItem()`&quot;">​</a></h3><p>Navigates to the item&#39;s view route by appending <code>/view/&lt;item._id&gt;</code> to the current route path.</p><h3 id="canedititem" tabindex="-1"><code>canEditItem()</code> <a class="header-anchor" href="#canedititem" aria-label="Permalink to &quot;`canEditItem()`&quot;">​</a></h3><p>Checks whether the current user has <code>update</code> permission for this item.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="edititem-scope-properties" tabindex="-1"><code>editItem(scope, properties)</code> <a class="header-anchor" href="#edititem-scope-properties" aria-label="Permalink to &quot;`editItem(scope, properties)`&quot;">​</a></h3><p>Navigates to the item&#39;s edit route. The path is built as <code>&lt;current path&gt;/edit/&lt;item._id&gt;[/&lt;properties&gt;|/&lt;scope&gt;]</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>scope</code> <em>(string, optional)</em>: An optional scope segment appended to the path.</li><li><code>properties</code> <em>(string, optional)</em>: When provided alongside <code>scope</code>, used as the trailing path segment instead of <code>scope</code>.</li></ul></li></ul><h3 id="canremoveitem" tabindex="-1"><code>canRemoveItem()</code> <a class="header-anchor" href="#canremoveitem" aria-label="Permalink to &quot;`canRemoveItem()`&quot;">​</a></h3><p>Checks whether the current user has <code>remove</code> permission for this item.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="removeitem-prompt-namefield" tabindex="-1"><code>removeItem(prompt, nameField)</code> <a class="header-anchor" href="#removeitem-prompt-namefield" aria-label="Permalink to &quot;`removeItem(prompt, nameField)`&quot;">​</a></h3><p>Removes the item from the service. Optionally shows a confirmation dialog first.</p><ul><li><strong>Parameters:</strong><ul><li><code>prompt</code> <em>(string, optional)</em>: Confirmation mode. <code>&#39;confirm&#39;</code> shows a yes/no dialog; <code>&#39;input&#39;</code> additionally requires the user to type the item name to confirm. Any other value (or omitting the parameter) removes without confirmation.</li><li><code>nameField</code> <em>(string, default <code>&#39;name&#39;</code>)</em>: The item field used as the display name in the confirmation dialog.</li></ul></li></ul><h3 id="exportitem" tabindex="-1"><code>exportItem()</code> <a class="header-anchor" href="#exportitem" aria-label="Permalink to &quot;`exportItem()`&quot;">​</a></h3><p>Exports the item as a JSON file. Uses Quasar&#39;s <code>exportFile</code> utility and shows a success or error notification.</p><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><ul><li><strong><code>created</code></strong>: calls <code>configureActions()</code> and subscribes to the <code>user-abilities-changed</code> event so that actions are refreshed whenever permissions change.</li><li><strong><code>beforeUnmount</code></strong>: unsubscribes from the <code>user-abilities-changed</code> event.</li></ul>',63),s=[d];function n(r,c,l,h,m,p){return o(),t("div",null,s)}const b=e(i,[["render",n]]);export{g as __pageData,b as default};
